<script setup lang="ts">
import { computed, onMounted, reactive, ref } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import PageFrame from '@/components/common/PageFrame.vue'
import EmptyState from '@/components/common/EmptyState.vue'
import { createPerformanceCycle, createPerformanceMetric, createPerformanceScheme, createSchemeVersion, enableSchemeVersion, fetchPerformanceCycles, fetchPerformanceMetrics, fetchPerformanceSchemes, publishPerformanceCycle, startPerformanceCycle, type PerformanceCycle, type PerformanceMetric, type PerformanceScheme } from '@/api/performance'

const metrics = ref<PerformanceMetric[]>([]); const schemes = ref<PerformanceScheme[]>([]); const cycles = ref<PerformanceCycle[]>([]); const loading = ref(false)
const metricDialog = ref(false); const schemeDialog = ref(false); const cycleDialog = ref(false); const versionDialog = ref(false); const schemeId = ref('')
const metric = reactive({ code: '', name: '', metricType: 'QUANTITATIVE', unit: '', scoreMethod: 'MANUAL', scoreConfig: '{"min":0,"max":100}', description: '', status: 'ACTIVE' })
const scheme = reactive({ code: '', name: '', applicabilityRule: '{"type":"ALL"}' }); const cycle = reactive({ code: '', name: '', schemeVersionId: '', startDate: '', endDate: '', selfDeadline: '', managerDeadline: '', appealDeadline: '', applicabilityRule: '{"type":"ALL"}' })
const enabledVersions = computed(() => schemes.value.flatMap((s) => s.versions.filter((v) => v.status === 'ENABLED').map((v) => ({ id: v.id, label: `${s.code} v${v.versionNo}` }))))
async function load() { loading.value = true; try { [metrics.value, schemes.value, cycles.value] = await Promise.all([fetchPerformanceMetrics(), fetchPerformanceSchemes(), fetchPerformanceCycles()]) } catch { ElMessage.error('无法加载绩效配置') } finally { loading.value = false } }
function json(value: string) { try { JSON.parse(value); return true } catch { ElMessage.warning('JSON 配置格式不正确'); return false } }
async function saveMetric() { if (!metric.code || !metric.name || !json(metric.scoreConfig)) return; try { await createPerformanceMetric({ ...metric, unit: metric.unit || null, description: metric.description || null }); metricDialog.value = false; ElMessage.success('指标已创建'); await load() } catch { ElMessage.error('指标保存失败') } }
async function saveScheme() { if (!scheme.code || !scheme.name || !json(scheme.applicabilityRule)) return; try { await createPerformanceScheme(scheme); schemeDialog.value = false; ElMessage.success('方案已创建'); await load() } catch { ElMessage.error('方案保存失败') } }
async function saveVersion() { const active = metrics.value.find((m) => m.status === 'ACTIVE'); if (!active) return ElMessage.warning('请先创建启用状态的指标'); try { await createSchemeVersion(schemeId.value, { evaluationStages: '["SELF","MANAGER"]', items: [{ metricId: active.id, weight: 100, scoreMethod: active.scoreMethod, scoreConfig: active.scoreConfig, sortNo: 1 }], levelRules: [{ levelCode: 'A', minScore: 90, maxScore: 100, includeMin: true, includeMax: true }, { levelCode: 'B', minScore: 0, maxScore: 90, includeMin: true, includeMax: false }] }); versionDialog.value = false; ElMessage.success('草稿版本已创建'); await load() } catch { ElMessage.error('版本保存失败') } }
function draftVersions(versions: PerformanceScheme['versions']) { return versions.filter((version) => version.status === 'DRAFT') }
async function enable(id: string, version: number) { try { await ElMessageBox.confirm('启用后版本不可修改，是否继续？', '启用版本', { type: 'warning' }); await enableSchemeVersion(id, version); await load() } catch { /* cancellation */ } }
async function saveCycle() { if (!cycle.code || !cycle.name || !cycle.schemeVersionId || !cycle.startDate || !cycle.endDate || !cycle.selfDeadline || !cycle.managerDeadline || !json(cycle.applicabilityRule)) return; try { await createPerformanceCycle({ ...cycle, appealDeadline: cycle.appealDeadline || null }); cycleDialog.value = false; ElMessage.success('周期已创建'); await load() } catch { ElMessage.error('周期创建失败') } }
async function start(row: PerformanceCycle) { try { await ElMessageBox.confirm('将为所有在职员工生成任务快照，操作不可撤销。', '启动周期', { type: 'warning' }); await startPerformanceCycle(row.id, row.version); await load() } catch { /* cancellation */ } }
async function publish(row: PerformanceCycle) { try { await ElMessageBox.confirm('仅已完成主管评分的任务会发布，是否继续？', '发布绩效结果', { type: 'warning' }); const result = await publishPerformanceCycle(row.id, row.version); ElMessage.success(`已发布 ${result.publishedCount} 项结果`); await load() } catch { /* cancellation */ } }
onMounted(load)
</script>
<template><PageFrame title="绩效配置" description="维护指标、方案版本与考核周期；启动后生成员工任务快照。"><template #actions><el-button @click="load">刷新</el-button></template><el-tabs v-loading="loading"><el-tab-pane label="指标"><el-button type="primary" @click="metricDialog = true">新增指标</el-button><el-table :data="metrics" class="data-table"><el-table-column prop="code" label="编码"/><el-table-column prop="name" label="名称"/><el-table-column prop="metricType" label="类型"/><el-table-column prop="status" label="状态"/></el-table><EmptyState v-if="!metrics.length" title="暂无绩效指标" description="创建指标后可加入绩效方案。"/></el-tab-pane><el-tab-pane label="方案"><el-button type="primary" @click="schemeDialog = true">新增方案</el-button><el-table :data="schemes" class="data-table"><el-table-column prop="code" label="编码"/><el-table-column prop="name" label="名称"/><el-table-column label="版本"><template #default="{ row }"><el-tag v-for="v in row.versions" :key="v.id" class="version" :type="v.status === 'ENABLED' ? 'success' : 'info'">v{{ v.versionNo }} {{ v.status }}</el-tag></template></el-table-column><el-table-column label="操作"><template #default="{ row }"><el-button text @click="schemeId = row.id; versionDialog = true">创建版本</el-button><el-button v-for="v in draftVersions(row.versions)" :key="v.id" text type="primary" @click="enable(v.id, v.version)">启用 v{{ v.versionNo }}</el-button></template></el-table-column></el-table></el-tab-pane><el-tab-pane label="考核周期"><el-button type="primary" :disabled="!enabledVersions.length" @click="cycle.schemeVersionId = enabledVersions[0]?.id ?? ''; cycleDialog = true">新增周期</el-button><el-table :data="cycles" class="data-table"><el-table-column prop="code" label="编码"/><el-table-column prop="name" label="名称"/><el-table-column prop="startDate" label="开始"/><el-table-column prop="endDate" label="结束"/><el-table-column prop="status" label="状态"/><el-table-column label="操作"><template #default="{ row }"><el-button v-if="row.status === 'DRAFT'" text type="primary" @click="start(row)">启动</el-button><el-button v-else-if="row.status === 'STARTED'" text type="success" @click="publish(row)">发布</el-button></template></el-table-column></el-table></el-tab-pane></el-tabs><el-dialog v-model="metricDialog" title="新增绩效指标" width="520"><el-form label-position="top"><el-form-item label="编码"><el-input v-model="metric.code"/></el-form-item><el-form-item label="名称"><el-input v-model="metric.name"/></el-form-item><el-form-item label="评分配置 JSON"><el-input v-model="metric.scoreConfig" type="textarea"/></el-form-item></el-form><template #footer><el-button @click="metricDialog = false">取消</el-button><el-button type="primary" @click="saveMetric">保存</el-button></template></el-dialog><el-dialog v-model="schemeDialog" title="新增绩效方案" width="520"><el-form label-position="top"><el-form-item label="编码"><el-input v-model="scheme.code"/></el-form-item><el-form-item label="名称"><el-input v-model="scheme.name"/></el-form-item><el-form-item label="适用范围 JSON"><el-input v-model="scheme.applicabilityRule" type="textarea"/></el-form-item></el-form><template #footer><el-button @click="schemeDialog = false">取消</el-button><el-button type="primary" @click="saveScheme">保存</el-button></template></el-dialog><el-dialog v-model="versionDialog" title="创建草稿版本" width="460"><p>将使用第一个启用状态的指标创建 100% 权重、员工自评和主管评分的草稿版本。</p><template #footer><el-button @click="versionDialog = false">取消</el-button><el-button type="primary" @click="saveVersion">创建</el-button></template></el-dialog><el-dialog v-model="cycleDialog" title="新增考核周期" width="560"><el-form label-position="top"><el-form-item label="编码"><el-input v-model="cycle.code"/></el-form-item><el-form-item label="名称"><el-input v-model="cycle.name"/></el-form-item><el-form-item label="启用版本"><el-select v-model="cycle.schemeVersionId"><el-option v-for="v in enabledVersions" :key="v.id" :label="v.label" :value="v.id"/></el-select></el-form-item><el-form-item label="开始与结束"><el-date-picker v-model="cycle.startDate" value-format="YYYY-MM-DD"/><el-date-picker v-model="cycle.endDate" value-format="YYYY-MM-DD"/></el-form-item><el-form-item label="自评截止"><el-date-picker v-model="cycle.selfDeadline" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss"/></el-form-item><el-form-item label="评分截止"><el-date-picker v-model="cycle.managerDeadline" type="datetime" value-format="YYYY-MM-DDTHH:mm:ss"/></el-form-item></el-form><template #footer><el-button @click="cycleDialog = false">取消</el-button><el-button type="primary" @click="saveCycle">保存</el-button></template></el-dialog></PageFrame></template><style scoped>.version{margin:2px}</style>
